cd /app && python3 -c "
import json,re,random,chess
pipe=json.load(open('/app/re.json'))
def run(fen):
    s=fen
    for pat,repl in pipe: s=re.sub(pat,repl,s)
    return [' '.join(x.split(' ')[:-2]) for x in s.split('\n')]
def check(fen):
    ours=run(fen)
    b=chess.Board(fen)
    real=set()
    for m in b.legal_moves:
        if m.promotion and m.promotion!=chess.QUEEN: continue
        c=b.copy(); c.push(m); real.add(' '.join(c.fen().split(' ')[:-2]))
    for x in ours:
        if not (x in real or x.rpartition(' ')[0]+' -' in real):
            return ('EXTRA',fen,x)
    if len(ours)!=len(real):
        return ('COUNT',fen,len(ours),len(real))
    return None
random.seed(1)
fails=0; tested=0
for g in range(400):
    b=chess.Board()
    depth=random.randint(0,60)
    for _ in range(depth):
        ms=list(b.legal_moves)
        if not ms: break
        b.push(random.choice(ms))
        if b.turn==chess.WHITE and b.legal_moves:
            r=check(b.fen()); tested+=1
            if r: print(r); fails+=1
            if fails>15: break
    if fails>15: break
print('tested',tested,'fails',fails)
"
